  ('dietitian-moex-07955', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某病一經罹患後即終生免疫。某地居民15000人，罹患該病的紀錄如下：95年2月病例數為20人、95年4 月新增加病例數15人、95年6月新增加病例數17人、95年8月新增加病例數為20人，則95年2月的 盛行率為何？', '["20/15000", "20/14980", "20/14928", "20/14965"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "fd4995c65619", "answer_pdf_sha1": "f1cf22412642", "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "109", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 40, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-07956', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '一大卡（kilocalorie）等於多少千焦耳（kilojoule）？', '["3.141", "4.184", "5.841", "6.148"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "f9268d3fe5e7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 1, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
